import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAppStore } from '../../store/useAppStore';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Building, Upload, AlertTriangle, Save, Image as ImageIcon } from 'lucide-react';

const RESERVED_SLUGS = ['admin', 'super-admin', 'login', 'api', 'assets', 'system', 'home', 'perfil', 'busca', 'hub', 'biblioteca'];

export const AdminSettings = () => {
  const { linkName } = useParams();
  const navigate = useNavigate();
  const { companies, updateCompany } = useAppStore();

  const company = companies.find(c => c.linkName === linkName);

  const [formData, setFormData] = useState({
    name: '',
    linkName: '',
    logoUrl: '',
    heroImage: '',
    heroTitle: '',
    heroSubtitle: '',
    active: true
  });

  // Inicializa o form com os dados da empresa
  useEffect(() => {
    if (company) {
      setFormData({
        name: company.name,
        linkName: company.linkName,
        logoUrl: company.logoUrl || '',
        heroImage: company.heroImage || '',
        heroTitle: company.heroTitle || '',
        heroSubtitle: company.heroSubtitle || '',
        active: company.active
      });
    }
  }, [company]);

  if (!company) return null;

  const handleLinkNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newLink = e.target.value.toLowerCase().replace(/[\s\W-]+/g, '');
    setFormData(prev => ({ ...prev, linkName: newLink }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'logoUrl' | 'heroImage') => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Limite de 10MB para o arquivo bruto
    if (file.size > 10 * 1024 * 1024) {
      toast.error('A imagem é muito grande (máximo 10MB).');
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        // Limita a resolução para proteger a memória (Hero = 1280px, Logo = 400px)
        const maxWidth = field === 'heroImage' ? 1280 : 400;

        if (width > maxWidth) {
          height = Math.round((height * maxWidth) / width);
          width = maxWidth;
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        if (ctx) {
          // Fundo branco para caso a imagem tenha transparência (útil para JPEG)
          ctx.fillStyle = '#FFFFFF';
          ctx.fillRect(0, 0, width, height);
          ctx.drawImage(img, 0, 0, width, height);

          // Comprime como JPEG com 80% de qualidade
          const compressedUrl = canvas.toDataURL('image/jpeg', 0.8);
          setFormData(prev => ({ ...prev, [field]: compressedUrl }));
        } else {
          // Fallback caso o canvas falhe
          setFormData(prev => ({ ...prev, [field]: event.target?.result as string }));
        }
      };
      img.src = event.target?.result as string;
    };
    reader.readAsDataURL(file);

    // Reseta o input para permitir upload da mesma imagem se necessário
    e.target.value = '';
  };

